select option:checked { background:var(--bg-active) !important; color:var(--primary-500) !important; font-weight:600 !important; }
select option:hover { background:var(--bg-hover) !important; }

/* === n8n 可能使用的自定义下拉组件兼容 === */
.multiselect, [class*="dropdown"], [class*="select-"]:not(select), [class*="vs__"] { border-radius:10px !important; font-family:inherit !important; }
.multiselect__tags, [class*="dropdown-trigger"], [class*="select-trigger"], .vs__dropdown-toggle { border-radius:10px !important; border:1px solid var(--border-strong) !important; background:var(--bg-card) !important; padding:9px 14px !important; min-height:42px !important; font-size:14px !important; color:var(--text-primary) !important; transition:border-color 200ms ease-out, box-shadow 200ms ease-out !important; }
.multiselect--active .multiselect__tags, .multiselect__tags:focus-within, [class*="dropdown-trigger"]:focus, [class*="select-trigger"]:focus-within, .vs--open .vs__dropdown-toggle { border-color:var(--primary-400) !important; box-shadow:0 0 0 4px rgba(74,144,217,0.12) !important; }
.multiselect__single, .multiselect__placeholder, .vs__selected { color:var(--text-primary) !important; font-size:14px !important; padding:0 !important; margin:0 !important; line-height:24px !important; }
