.multiselect__content-wrapper, [class*="dropdown-menu"], [class*="select-panel"], .vs__dropdown-menu { border-radius:12px !important; border:1px solid var(--border) !important; background:var(--bg-card) !important; box-shadow:var(--shadow-3) !important; margin-top:6px !important; padding:6px !important; overflow:hidden !important; }
.multiselect__option, [class*="dropdown-item"], [class*="select-option"], .vs__dropdown-option { padding:9px 14px 9px 18px !important; font-size:14px !important; color:var(--text-secondary) !important; border-radius:8px !important; position:relative !important; transition:background 160ms ease-out, color 160ms ease-out !important; cursor:pointer !important; }
.multiselect__option::before, [class*="dropdown-item"]::before, .vs__dropdown-option::before { content:'' !important; position:absolute !important; left:6px !important; top:50% !important; width:2px !important; height:16px !important; border-radius:2px !important; background:linear-gradient(180deg, var(--primary-400), var(--primary-600)) !important; transform:translateY(-50%) scaleY(0) !important; transition:transform 200ms ease-out !important; }
.multiselect__option--highlight, .multiselect__option:hover, [class*="dropdown-item"]:hover, [class*="select-option"]:hover, .vs__dropdown-option--highlight { background:var(--bg-hover) !important; color:var(--text-primary) !important; }
.multiselect__option--highlight::before, .multiselect__option:hover::before, [class*="dropdown-item"]:hover::before, .vs__dropdown-option--highlight::before { transform:translateY(-50%) scaleY(1) !important; }
.multiselect__option--selected, [class*="dropdown-item"][aria-selected="true"], [class*="select-option--selected"], .vs__dropdown-option--selected { background:var(--bg-active) !important; color:var(--primary-500) !important; font-weight:600 !important; }
