button[type=submit], .btn-primary, button.submit { background:linear-gradient(180deg, var(--primary-400), var(--primary-500)) !important; color:#fff !important; border:none !important; padding:12px 28px !important; font-size:14px !important; font-weight:600 !important; border-radius:10px !important; cursor:pointer !important; box-shadow:var(--shadow-brand), inset 0 1px 0 rgba(255,255,255,0.22) !important; transition:transform 150ms ease-out, box-shadow 150ms ease-out !important; margin-top:8px !important; }
