// MML 「静水深流」品牌风格 HTML 渲染（inline style 版）
const raw = $input.first().json.choices[0].message.content || '';
const formMeta = $('On form submission').first().json;

const esc = (s) => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

function md2html(raw) {
  let h = esc(raw);
  h = h.replace(/^#### (.*)$/gm, '<h4>$1</h4>');
  h = h.replace(/^### (.*)$/gm, '<h3>$1</h3>');
  h = h.replace(/^## (.*)$/gm, '<h2>$1</h2>');
  h = h.replace(/^# (.*)$/gm, '<h1>$1</h1>');
  h = h.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  h = h.replace(/(^|[^*])\*([^*\n]+?)\*([^*]|$)/g, '$1<em>$2</em>$3');
  h = h.replace(/`([^`\n]+)`/g, '<code>$1</code>');
  h = h.replace(/^> (.*)$/gm, '<blockquote>$1</blockquote>');
  h = h.replace(/^(?:- |\* )(.*)$/gm, '<li>$1</li>');
  h = h.replace(/(<li>[\s\S]*?<\/li>)(?!\s*<li>)/g, '<ul>$1</ul>');
  return h.split(/\n{2,}/).map(b => {
    if (/^<(h\d|ul|blockquote)/i.test(b.trim())) return b;
    return '<p>' + b.replace(/\n/g, '<br/>') + '</p>';
  }).join('\n');
}

const skillName = (formMeta.Skill || '').replace(/-perspective$/, '').replace(/-/g, ' ');

const eyebrowStyle = "font-family:'SF Mono',ui-monospace,monospace;font-size:11px;font-weight:500;letter-spacing:0.18em;text-transform:uppercase;color:#3A78C2";
const nameStyle = "font-family:Georgia,serif;font-style:italic;font-weight:400;letter-spacing:0;text-transform:capitalize;color:#1A1D20;font-size:13px;padding-left:4px";
const proseStyle = "font-size:16px;line-height:1.75;color:#4A5057;max-width:62ch";

const body = `<div style="max-width:880px;margin:60px auto;padding:0 24px;font-family:-apple-system,BlinkMacSystemFont,'PingFang SC',sans-serif;color:#1A1D20;line-height:1.7"><article style="background:#fff;border:1px solid #ECEEE8;border-radius:16px;box-shadow:0 1px 2px rgba(16,24,40,0.04),0 6px 16px -4px rgba(16,24,40,0.06);overflow:hidden;position:relative"><div style="height:4px;background:linear-gradient(120deg,#4A90D9 0%,#6FC9E8 35%,#B4A7E8 68%,#F0B4D8 100%)"></div><div style="padding:56px 64px 48px"><div style="${eyebrowStyle};margin:0 0 18px">PERSPECTIVE · <em style="${nameStyle}">${esc(skillName)}</em></div><div style="display:flex;flex-wrap:wrap;gap:8px;margin:0 0 32px"><span style="display:inline-block;padding:4px 12px;background:#EBF3FB;color:#2D61A5;border:1px solid rgba(74,144,217,0.18);border-radius:100px;font-size:12px;font-weight:500;font-family:'SF Mono',ui-monospace,monospace">${esc(formMeta.Provider || '')} · ${esc(formMeta.Model || '')}</span><span style="display:inline-block;padding:4px 12px;background:transparent;color:#8B8F86;border:1px solid #DEE0D9;border-radius:100px;font-size:12px;font-weight:500;font-family:'SF Mono',ui-monospace,monospace">${esc(formMeta.Language || '')}</span></div><blockquote style="border-left:2px solid #4A90D9;padding:8px 0 8px 20px;margin:0 0 40px;font-family:Georgia,'Times New Roman',serif;font-style:italic;font-size:19px;line-height:1.55;color:#1A1D20">${esc(formMeta.Question || '')}</blockquote><div style="${proseStyle}">${md2html(raw)}</div><div style="display:flex;align-items:center;gap:16px;margin:48px 0 0;padding-top:28px;border-top:1px solid #E2E4DD"><span style="flex:1;height:1px;background:#E2E4DD"></span><span style="font-family:Georgia,serif;font-style:italic;font-size:12px;color:#8B8F86">慢慢来 · 静水深流</span><span style="flex:1;height:1px;background:#E2E4DD"></span></div></div></article></div>`;

return [{ json: { formSubmittedText: body } }];
